/// <reference path="../node/index.d.ts" />

import * as http from 'http';

export = express;

declare function express(): express.Application;

declare namespace express {
  interface Application extends http.RequestListener {
    (req: http.IncomingMessage, res: http.ServerResponse): void;
    use(...args: any[]): any;
    get(...args: any[]): any;
    post(...args: any[]): any;
    put(...args: any[]): any;
    delete(...args: any[]): any;
    listen(...args: any[]): any;
  }

  interface Request {
    [key: string]: any;
  }

  interface Response {
    send(...args: any[]): any;
    json(...args: any[]): any;
    status(...args: any[]): any;
  }

  type NextFunction = (err?: any) => void;
}

